<span class="line">            dynamicFont <span class="token operator">=</span> dynamicFont<span class="token punctuation">.</span><span class="token function">deriveFont</span><span class="token punctuation">(</span>size<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
